    87→sds activeDefragSds(sds sdsptr) {
    88→    void* ptr = sdsAllocPtr(sdsptr);
    89→    void* newptr = activeDefragAlloc(ptr);
    90→    if (newptr) {
    91→        size_t offset = sdsptr - (char*)ptr;
    92→        sdsptr = (char*)newptr + offset;
